let lastTime = 0;
let playerX = 100;
let playerY = 100;

function update(delta) {
    const newX = playerX + (delta / 16);
    const newY = playerY + (delta / 16);
    
    if (newX > 800 || newX < 0) {
        playerX = Math.max(Math.min(newX, 800), 0);
    }
    if (newY > 600 || newY < 0) {
        playerY = Math.max(Math.min(newY, 600), 0);
    }

    document.getElementById('player').style.left = `${playerX}px`;
    document.getElementById('player').style.top = `${playerY}px`;

    const distanceTraveled = Math.sqrt((newX - lastTime) ** 2 + (newY - playerY) ** 2);
    console.log(`Distance traveled: ${distanceTraveled}`);
}

function gameLoop() {
    const currentTime = performance.now();
    const delta = currentTime - lastTime;
    update(delta);
    lastTime = currentTime;

    requestAnimationFrame(gameLoop);
}

document.addEventListener('DOMContentLoaded', () => {
    document.getElementById('player').style.position = 'absolute';
    lastTime = performance.now();
    gameLoop();
});